sql:
SELECT strftime('%Y', proposed_date) AS proposed_year, COUNT(*) AS resolution_count
FROM resolutions
GROUP BY proposed_year;

SELECT resolution_id, COUNT(voting_session_id) AS session_count, voting_end_date
FROM voting_sessions
GROUP BY resolution_id, voting_end_date;

SELECT AVG(impact_score) AS average_impact_score
FROM resolution_impact
WHERE impact_type = 'operational';

SELECT MAX(impact_score) AS max_financial_impact
FROM resolution_impact
WHERE impact_type = 'financial';

external_knowledge:
Human rights-related resolutions refer to resolutions categorized under 'HUMAN RIGHTS' in the company's database; 
Financial impact scores are used to quantify the financial effects of resolutions;
Stakeholders are entities with an interest in the resolutions.

sql:
SELECT status_name, COUNT(status_id) AS status_count
FROM resolution_status
GROUP BY status_name;

SELECT status_name, description
FROM resolution_status
WHERE is_final = 1;

SELECT resolution_number, resolution_text
FROM resolutions
WHERE resolution_id = 0;

SELECT AVG(impact_score) AS average_impact_score
FROM resolution_impact
WHERE impact_type = 'operational';

SELECT AVG(resolution_count) AS avg_resolutions_per_company
FROM (
  SELECT company_id, COUNT(*) AS resolution_count
  FROM resolutions
  GROUP BY company_id
);

SELECT COUNT(*) 
FROM voting_sessions 
WHERE voting_start_date LIKE '2023-04%';

SELECT COUNT(*) AS number_of_resolutions
FROM resolutions
WHERE company_id = (SELECT company_id FROM companies WHERE company_name = 'CITIGROUP INC');

SELECT resolution_id, COUNT(*) AS vote_count
FROM resolution_votes
GROUP BY resolution_id;

SELECT document_type, COUNT(*) AS document_count
FROM resolution_documents
GROUP BY document_type;

SELECT stakeholder_name
FROM resolution_stakeholders
WHERE stakeholder_role = 'board member';

SELECT COUNT(*) AS number_of_proposed_resolutions
FROM resolutions
WHERE resolution_status_id = (SELECT status_id FROM resolution_status WHERE status_name = 'PROPOSED');
